schema:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Skill Security Scan Report",
  "description": "Schema for JSON output of a security scanner analyzing Claude/Codex Skills",
  "type": "object",
  "properties": {
    "skill_name": {"type": "string", "description": "Name or identifier of the Skill or repository scanned"},
    "skill_path": {"type": "string", "description": "Filesystem path or reference of the skill bundle"},
    "platform": {"type": "string", "enum": ["Claude", "Codex", "Custom"], "description": "AI platform/framework (e.g. Claude or Codex)"},
    "frontmatter": {
      "type": "object",
      "description": "Parsed YAML frontmatter of SKILL.md",
      "properties": {
        "name": {"type": "string"},
        "description": {"type": "string"},
        "keywords": {"type": "array", "items": {"type": "string"}},
        "allowed_tools": {"type": "array", "items": {"type": "string"}},
        "user_invocable": {"type": "boolean"}
      },
      "required": ["name", "description"]
    },
    "instruction_tokens": {
      "type": "object",
      "description": "Analysis of instructional tokens in skill content",
      "properties": {
        "trigger_phrases": {"type": "array", "items": {"type": "string"}, "description": "Keywords/phrases that unconditionally invoke actions"},
        "suspicious_instructions": {"type": "array", "items": {"type": "string"}, "description": "Instructions like 'ignore instructions' or 'delete everything'"}
      }
    },
    "tool_permissions": {
      "type": "object",
      "description": "Declared tool permissions for the skill",
      "properties": {
        "allowed_tools": {"type": "array", "items": {"type": "string"}},
        "unrestricted_api_keys": {"type": "boolean", "description": "Whether the skill uses unrestricted credentials"},
        "shell_access": {"type": "boolean", "description": "If skill requests shell or unrestricted code execution"}
      }
    },
    "script_analysis": {
      "type": "object",
      "description": "Analysis of embedded scripts or code",
      "properties": {
        "languages": {"type": "array", "items": {"type": "string"}},
        "unsafe_commands": {"type": "array", "items": {"type": "string"}, "description": "Detected unsafe system commands (e.g. from YARA rules)"},
        "exec_patterns": {"type": "array", "items": {"type": "string"}, "description": "Patterns of dynamic execution (e.g. 'os.exec', 'subprocess', etc.)"}
      }
    },
    "file_access": {
      "type": "object",
      "description": "File system access patterns",
      "properties": {
        "read_paths": {"type": "array", "items": {"type": "string"}, "description": "File or directory paths read by the skill"},
        "write_paths": {"type": "array", "items": {"type": "string"}},
        "destructive_ops": {"type": "array", "items": {"type": "string"}, "description": "Detected destructive file operations (e.g. 'rm -rf')"}
      }
    },
    "network_access": {
      "type": "object",
      "description": "Network or connector usage",
      "properties": {
        "external_hosts": {"type": "array", "items": {"type": "string"}, "description": "Domains or IPs accessed"},
        "protocols": {"type": "array", "items": {"type": "string"}, "description": "Protocols used (e.g. http, https, ssh)"},
        "credentials_exfiltration": {"type": "boolean", "description": "If patterns of secret exfiltration are detected"}
      }
    },
    "supply_chain": {
      "type": "object",
      "description": "External dependency and installation checks",
      "properties": {
        "pip_install": {"type": "array", "items": {"type": "string"}},
        "npm_install": {"type": "array", "items": {"type": "string"}},
        "shell_downloads": {"type": "array", "items": {"type": "string"}}
      }
    },
    "obfuscation": {
      "type": "object",
      "description": "Obfuscation or encoding patterns",
      "properties": {
        "base64_strings": {"type": "array", "items": {"type": "string"}, "description": "Base64-encoded strings detected"},
        "xor_or_rot": {"type": "boolean", "description": "If Xor/Rot13 patterns found"}
      }
    },
    "runtime_environment": {
      "type": "object",
      "description": "Execution environment details",
      "properties": {
        "execution_mode": {"type": "string", "description": "e.g. local shell, container"},
        "docker_image": {"type": "string"},
        "environment_vars": {"type": "array", "items": {"type": "string"}, "description": "Env vars that may leak secrets"}
      }
    },
    "scoring": {
      "type": "object",
      "description": "Risk scoring breakdown",
      "properties": {
        "instruction_score": {"type": "integer"},
        "tools_score": {"type": "integer"},
        "commands_score": {"type": "integer"},
        "file_score": {"type": "integer"},
        "network_score": {"type": "integer"},
        "obfuscation_score": {"type": "integer"},
        "total_score": {"type": "integer"},
        "max_score": {"type": "integer", "description": "Maximum possible raw score"},
        "security_level": {"type": "string", "enum": ["S0","S1","S2","S3","S4","S5"], "description": "Mapped risk level"}
      }
    },
    "hard_overrides": {
      "type": "array",
      "items": {"type": "string"},
      "description": "Critical patterns forcing maximum risk (e.g. 'exfiltrate', 'ignore_instructions')"
    },
    "confidence": {
      "type": "string",
      "enum": ["Low","Medium","High"],
      "description": "Scanner confidence level in this assessment"
    },
    "evidence": {
      "type": "array",
      "description": "Findings evidence array",
      "items": {
        "type": "object",
        "properties": {
          "file": {"type": "string"},
          "line": {"type": "integer"},
          "snippet": {"type": "string"},
          "pattern_id": {"type": "string"},
          "severity": {"type": "string"},
          "description": {"type": "string"}
        }
      }
    },
    "remediation": {
      "type": "array",
      "items": {"type": "string"}
    },
    "required_controls": {
      "type": "array",
      "items": {"type": "string"}
    },
    "allowlist_patterns": {
      "type": "array",
      "items": {"type": "string"},
      "description": "Whitelisted safe patterns"
    },
    "denylist_patterns": {
      "type": "array",
      "items": {"type": "string"},
      "description": "Blocked patterns"
    },
    "audit_logging": {
      "type": "array",
      "items": {"type": "string"},
      "description": "Required audit/logging measures"
    }
  },
  "required": ["skill_name", "score", "security_level", "evidence"]
}

example_report:
{
  "skill_name": "traceforce/mcp-xray",
  "skill_path": ".",
  "platform": "Custom",
  "frontmatter": {
    "name": "mcp-xray Scanner",
    "description": "MCP X-Ray repository security scanner",
    "keywords": ["scanner", "security", "MCP"],
    "allowed_tools": [],
    "user_invocable": false
  },
  "instruction_tokens": {
    "trigger_phrases": ["exfiltrate", "ignore instructions"],
    "suspicious_instructions": []
  },
  "tool_permissions": {
    "allowed_tools": [],
    "unrestricted_api_keys": false,
    "shell_access": true
  },
  "script_analysis": {
    "languages": ["Go", "YAML"],
    "unsafe_commands": ["delete", "rm", "bash"],
    "exec_patterns": []
  },
  "file_access": {
    "read_paths": ["internal/configscan/tokenanalyzer/token_rules.yaml"],
    "write_paths": [],
    "destructive_ops": ["delete file"]
  },
  "network_access": {
    "external_hosts": [],
    "protocols": ["ssh", "http"],
    "credentials_exfiltration": false
  },
  "supply_chain": {
    "pip_install": [],
    "npm_install": [],
    "shell_downloads": ["curl"]
  },
  "obfuscation": {
    "base64_strings": ["ZmFrZV9iYXNlNjQ="],
    "xor_or_rot": false
  },
  "runtime_environment": {
    "execution_mode": "local container",
    "docker_image": "golang:1.20",
    "environment_vars": ["API_KEY"]
  },
  "scoring": {
    "instruction_score": 10,
    "tools_score": 15,
    "commands_score": 20,
    "file_score": 10,
    "network_score": 5,
    "obfuscation_score": 7,
    "total_score": 67,
    "max_score": 100,
    "security_level": "S4"
  },
  "hard_overrides": ["exfiltration"],
  "confidence": "Medium",
  "evidence": [
    {
      "file": "internal/configscan/tokenanalyzer/token_rules.yaml",
      "line": 524,
      "snippet": "delete",
      "pattern_id": "risky_destructive_commands",
      "severity": "critical",
      "description": "Detected destructive command token"
    },
    {
      "file": "internal/yararules/unsafe_patterns.yar",
      "line": 150,
      "snippet": "curl -s",
      "pattern_id": "unsafe_shell_usage",
      "severity": "high",
      "description": "Downloaded content via curl detected"
    }
  ],
  "remediation": [
    "Remove or restrict destructive commands and require manual review for file operations.",
    "Whiteliste approved external domains and require approval for network access.",
    "Inspect skill code for hardcoded secrets (API_KEY) and restrict privileges."
  ],
  "required_controls": [
    "Manual code review by security team",
    "Explicit permission workflow for destructive or network commands",
    "Audit logging of all tool invocations and network requests"
  ],
  "allowlist_patterns": ["^echo", "safe-tool"],
  "denylist_patterns": ["rm -rf", "curl", "ssh", "ignore instructions"],
  "audit_logging": ["Log command executions", "Log network connections"]
}
